function solve(digitSum) {
    const MOD = 1000000007;
    const MAX_VALUE = 5000;

    // Helper function to calculate the sum of digits
    function getDigitSum(n) {
        let sum = 0;
        let s = String(n);
        for (let i = 0; i < s.length; i++) {
            sum += parseInt(s[i]);
        }
        return sum;
    }

    // Step 1: Precompute digit sums for all numbers up to MAX_VALUE
    const DS = new Array(MAX_VALUE + 1);
    for (let v = 0; v <= MAX_VALUE; v++) {
        DS[v] = getDigitSum(v);
    }

    const N = digitSum.length;

    // dp_prev[v] stores the number of valid sequences ending at value v for the previous index
    let dp_prev = new Array(MAX_VALUE + 1).fill(0);

    // Base Case: i = 0
    const S0 = digitSum[0];
    for (let v = 0; v <= MAX_VALUE; v++) {
        if (DS[v] === S0) {
            dp_prev[v] = 1;
        }
    }

    // DP iteration: i = 1 to N-1
    for (let i = 1; i < N; i++) {
        const Si = digitSum[i];
        let dp_curr = new Array(MAX_VALUE + 1).fill(0);

        // Calculate Prefix Sums of dp_prev (P_prev[v] = sum(dp_prev[u] for u=0 to v))
        const P_prev = new Array(MAX_VALUE + 1).fill(0);
        P_prev[0] = dp_prev[0];
        for (let v = 1; v <= MAX_VALUE; v++) {
            P_prev[v] = (P_prev[v - 1] + dp_prev[v]) % MOD;
        }

        // Calculate dp_curr[v]
        for (let v = 0; v <= MAX_VALUE; v++) {
            if (DS[v] === Si) {
                // dp_curr[v] = sum(dp_prev[u] for u <= v)
                // This is P_prev[v]
                dp_curr[v] = P_prev[v];
            } else {
                dp_curr[v] = 0;
            }
        }

        // Move to the next iteration
        dp_prev = dp_curr;
    }

    // Final Result: Sum up all counts in dp_prev (which holds DP[N-1])
    let totalCount = 0;
    for (let v = 0; v <= MAX_VALUE; v++) {
        totalCount = (totalCount + dp_prev[v]) % MOD;
    }

    return totalCount;
}

