    // DS[v] stores the sum of digits of v
    DS := make([]int64, MAX_VALUE+1)
    for v := int64(0); v <= MAX_VALUE; v++ {
        DS[v] = getDigitSum(v)
    }

    // dp_prev[v] stores the number of valid sequences ending exactly at value v for the previous index
    // Since the counts can reach MOD, we use int64.
    dp_prev := make([]int64, MAX_VALUE+1)

